/**
 * @summary Get all sticker orders (admin)
 */
export const getGetAdminStickerOrdersUrl = (
  params?: GetAdminStickerOrdersParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/admin/sticker-orders?${stringifiedParams}`
    : `/api/admin/sticker-orders`;
};

export const getAdminStickerOrders = async (
  params?: GetAdminStickerOrdersParams,
  options?: RequestInit,
): Promise<GetAdminStickerOrders200> => {
  return customFetch<GetAdminStickerOrders200>(
    getGetAdminStickerOrdersUrl(params),
    {
      ...options,
      method: "GET",
    },
  );
};

